import * as React from "react";

function YesFifthPageNo() {
  return (
    <>
      <div className="div-61">
        <div className="div-62">
          Private Pension
          <br />
          Withdrawal
        </div>
        <div className="div-63">
          Have you withdrawn money from any of your private pensions?
        </div>
        <div className="div-64">
          <div className="div-65">YES</div>
          <div className="div-66">NO</div>
        </div>
        <div className="div-67">Annual Allowance Calculation </div>
      </div>
      <style jsx>{`
        .div-61 {
          background-color: #fff;
          display: flex;
          max-width: 480px;
          width: 100%;
          flex-direction: column;
          align-items: center;
          font-size: 20px;
          color: #000;
          font-weight: 400;
          margin: 0 auto;
          padding: 80px 22px;
        }
        .div-62 {
          text-align: center;
          margin-top: 57px;
          width: 311px;
          font: 29px Inter, sans-serif;
        }
        .div-63 {
          text-align: center;
          font-family: Inter, sans-serif;
          margin-top: 63px;
        }
        .div-64 {
          display: flex;
          margin-top: 29px;
          width: 100%;
          max-width: 297px;
          gap: 20px;
          white-space: nowrap;
          justify-content: space-between;
        }
        .div-65 {
          font-family: Inter, sans-serif;
          border-radius: 22px;
          background-color: rgba(255, 255, 255, 1);
          border-color: rgba(0, 0, 0, 1);
          border-style: solid;
          border-width: 1px;
          align-items: start;
          justify-content: center;
          padding: 20px 48px;
        }
        .div-66 {
          font-family: Inter, sans-serif;
          border-radius: 22px;
          background-color: rgba(250, 233, 82, 1);
          border-color: rgba(0, 0, 0, 1);
          border-style: solid;
          border-width: 1px;
          align-items: start;
          justify-content: center;
          padding: 20px 52px;
        }
        .div-67 {
          font-family: Inter, sans-serif;
          border-radius: 22px;
          background-color: rgba(255, 255, 255, 1);
          border-color: rgba(0, 0, 0, 1);
          border-style: solid;
          border-width: 1px;
          align-self: stretch;
          margin-top: 87px;
          justify-content: center;
          padding: 20px 24px;
        }
      `}</style>
    </>
  );
}


export default YesFifthPageNo;
